const { execSync } = require('child_process');
const os = require('os');

export async function execute(limit = 20) {
  try {
    const command = os.platform() === 'win32' ? 'tasklist' : `ps -eo pid,ppid,user,%cpu,%mem,comm --sort=-%cpu | head -n ${limit + 1}`;
    const output = execSync(command, { encoding: 'utf8', timeout: 5000 });
    return { success: true, processes: output };
  } catch (err: any) {
    return { success: false, error: err.message, stderr: err.stderr?.toString() };
  }
}
